{% extends "base.html" %}

{% block title %}Edit Todo -- Todo List{% endblock %}

{% block nav %}
<form method="post" action="/logout" class="nav-logout">
    <button type="submit" class="nav-logout__button">Sign out</button>
</form>
{% endblock %}

{% block content %}
<div class="auth-form">
    <h1>Edit Todo</h1>
    {% if let Some(error) = error_message %}
    <div class="auth-form__message auth-form__message--error" role="alert">
        {{ error }}
    </div>
    {% endif %}
    <form method="post" action="/todos/{{ todo_id }}/edit" class="auth-form__fields" novalidate>
        <div class="auth-form__group">
            <label for="title">Title</label>
            <input
                type="text"
                id="title"
                name="title"
                value="{{ current_title }}"
                maxlength="300"
                required
                autofocus
                {% if let Some(err) = error_message %}aria-describedby="title-error" aria-invalid="true"{% endif %}
            >
            {% if let Some(err) = error_message %}
            <p class="auth-form__error" id="title-error">{{ err }}</p>
            {% endif %}
        </div>
        <div class="auth-form__actions">
            <button type="submit" class="auth-form__submit">Save</button>
            <a href="/todos" class="auth-form__cancel">Cancel</a>
        </div>
    </form>
</div>
{% endblock %}

use crate::helpers::spawn_app;

/// Helper to register a user via the registration endpoint.
async fn register_user(address: &str, email: &str, password: &str) {
    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{address}/register"))
        .form(&[
            ("email", email),
            ("password", password),
            ("password_confirmation", password),
        ])
        .send()
        .await
        .expect("Failed to register user");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Registration should succeed with 303"
    );
}

#[tokio::test]
async fn get_login_returns_200_with_login_form() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/login", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/html"),
        "Expected text/html, got {content_type}"
    );

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("Sign in"), "Missing page heading");
    assert!(
        body.contains("Sign in -- Todo List"),
        "Missing descriptive page title"
    );

    // Form fields with labels
    assert!(
        body.contains("<label for=\"email\">Email</label>"),
        "Missing email label"
    );
    assert!(body.contains("type=\"email\""), "Missing email input");
    assert!(
        body.contains("autocomplete=\"email\""),
        "Missing autocomplete=\"email\" on email field"
    );
    assert!(
        body.contains("<label for=\"password\">Password</label>"),
        "Missing password label"
    );
    assert!(
        body.contains("autocomplete=\"current-password\""),
        "Missing autocomplete=\"current-password\" on password field"
    );

    // Submit button
    assert!(
        body.contains(">Sign in</button>"),
        "Submit button should say 'Sign in'"
    );

    // Link to register
    assert!(
        body.contains("Create account"),
        "Missing link to registration page"
    );
    assert!(
        body.contains("href=\"/register\""),
        "Missing register link href"
    );

    // No error states on initial load
    assert!(
        !body.contains("role=\"alert\""),
        "Should not show error alert on initial load"
    );
}

#[tokio::test]
async fn post_login_with_valid_credentials_redirects_to_todos() {
    let app = spawn_app().await;
    let email = "login@example.com";
    let password = "securepassword123";

    register_user(&app.address, email, password).await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/login", &app.address))
        .form(&[("email", email), ("password", password)])
        .send()
        .await
        .expect("Failed to execute request");

    let status = response.status().as_u16();
    let location = response
        .headers()
        .get("location")
        .map(|v| v.to_str().unwrap().to_string());
    let body = response.text().await.unwrap();

    assert_eq!(
        status, 303,
        "Expected 303 redirect after successful login. Body: {body}"
    );
    assert_eq!(
        location.as_deref(),
        Some("/todos"),
        "Should redirect to /todos after login"
    );
}

